 82→/// Trait for running commands within a sandbox policy.
 83→pub trait CommandRunner: Send + Sync {
 84→    fn run(&self, policy: &SandboxPolicy, request: &CommandRequest) -> PraxisResult<CommandResult>;
 85→}
 86→
 87→/// Local command runner that enforces sandbox policy via process controls.
 88→#[derive(Debug, Default)]
 89→pub struct LocalCommandRunner;
 90→
 91→impl LocalCommandRunner {
 92→    pub fn new() -> Self {
 93→        Self
 94→    }
 95→
 96→    /// Validate that cwd is within the workspace boundary.
 97→    fn validate_cwd(policy: &SandboxPolicy, cwd: &std::path::Path) -> PraxisResult<PathBuf> {
 98→        // Canonicalize both to handle symlinks
 99→        let canonical_workspace = policy.workspace_root.canonicalize().map_err(|e| {
100→            PraxisError::WorkspaceViolation(format!("cannot resolve workspace: {e}"))
101→        })?;
102→        let canonical_cwd = cwd
103→            .canonicalize()
104→            .map_err(|e| PraxisError::WorkspaceViolation(format!("cannot resolve cwd: {e}")))?;
105→
106→        if !canonical_cwd.starts_with(&canonical_workspace) {
107→            return Err(PraxisError::PathOutsideWorkspace {
108→                path: cwd.display().to_string(),
109→            });
110→        }
111→        Ok(canonical_cwd)
112→    }
113→
114→    /// Filter environment variables through the allow list.
115→    fn filter_env(policy: &SandboxPolicy, requested: &[(String, String)]) -> Vec<(String, String)> {
116→        requested
117→            .iter()
118→            .filter(|(key, _)| policy.allowed_env.contains(key))
119→            .cloned()
120→            .collect()
121→    }
122→
123→    /// Truncate output to the maximum allowed size.
124→    fn truncate(output: Vec<u8>, max_bytes: usize) -> String {
125→        let mut bytes = output;
126→        if bytes.len() > max_bytes {
127→            bytes.truncate(max_bytes);
128→        }
129→        String::from_utf8_lossy(&bytes).into_owned()
130→    }
131→}
132→
133→impl CommandRunner for LocalCommandRunner {
134→    fn run(&self, policy: &SandboxPolicy, request: &CommandRequest) -> PraxisResult<CommandResult> {
135→        if !policy.shell_enabled {
136→            return Err(PraxisError::Sandbox(
137→                "shell execution is disabled by policy".into(),
138→            ));
139→        }
140→
141→        let canonical_cwd = Self::validate_cwd(policy, &request.cwd)?;
142→        let filtered_env = Self::filter_env(policy, &request.env);
143→
144→        debug!(
145→            executable = %request.executable,
146→            cwd = %canonical_cwd.display(),
147→            "executing command"
148→        );
149→
150→        let mut cmd = std::process::Command::new(&request.executable);
151→        cmd.args(&request.args);
152→        cmd.current_dir(&canonical_cwd);
153→        cmd.env_clear();
154→        for (key, val) in &filtered_env {
155→            cmd.env(key, val);
156→        }
157→
158→        let mut child = cmd
159→            .stdout(std::process::Stdio::piped())
160→            .stderr(std::process::Stdio::piped())
161→            .spawn()
162→            .map_err(|e| PraxisError::CommandFailed(format!("spawn failed: {e}")))?;
163→
164→        let timeout = std::time::Duration::from_millis(policy.max_execution_ms);
165→        match wait_timeout::ChildExt::wait_timeout(&mut child, timeout) {
166→            Ok(Some(status)) => {
167→                let stdout =
168→                    Self::truncate(read_pipe(child.stdout.take()), policy.max_stdout_bytes);
169→                let stderr =
170→                    Self::truncate(read_pipe(child.stderr.take()), policy.max_stderr_bytes);
171→
172→                Ok(CommandResult {
173→                    exit_code: status.code().unwrap_or(-1),
174→                    stdout,
175→                    stderr,
176→                })
177→            }
178→            Ok(None) => {
179→                // Timed out — kill the child
180→                warn!(
181→                    executable = %request.executable,
182→                    timeout_ms = policy.max_execution_ms,
183→                    "command timed out, killing"
184→                );
185→                let _ = child.kill();
186→                let _ = child.wait();
187→                Ok(CommandResult {
188→                    exit_code: -1,
189→                    stdout: String::new(),
190→                    stderr: format!("command timed out after {}ms", policy.max_execution_ms),
191→                })
192→            }
193→            Err(e) => Err(PraxisError::CommandFailed(format!("wait failed: {e}"))),
194→        }
195→    }
196→}
197→
198→/// Read all bytes from an optional pipe.
199→fn read_pipe(pipe: Option<impl std::io::Read>) -> Vec<u8> {
200→    let Some(mut pipe) = pipe else {
201→        return Vec::new();
202→    };
203→    let mut buf = Vec::new();
204→    let _ = std::io::Read::read_to_end(&mut pipe, &mut buf);
205→    buf
206→}
