250→// ── GlobTool ─────────────────────────────────────────────────────────
251→
252→/// Searches for files matching a glob pattern within the workspace.
253→pub struct GlobTool {
254→    fs: Arc<dyn FsPort>,
255→}
256→
257→impl GlobTool {
258→    pub fn new(fs: Arc<dyn FsPort>) -> Self {
259→        Self { fs }
260→    }
261→}
262→
263→impl Tool for GlobTool {
264→    fn definition(&self) -> ToolDefinition {
265→        ToolDefinition {
266→            name: "glob".into(),
267→            description: "Search for files matching a glob pattern within the workspace.".into(),
268→            input_schema: json!({
269→                "type": "object",
270→                "properties": {
271→                    "pattern": { "type": "string", "description": "Glob pattern (e.g. **/*.rs)" },
272→                    "path": { "type": "string", "description": "Base directory (optional, defaults to workspace root)" }
273→                },
274→                "required": ["pattern"]
275→            }),
276→            title: Some("Glob Search".into()),
277→            output_schema: None,
278→            annotations: Some(ToolAnnotations {
279→                read_only: true,
280→                idempotent: true,
281→                ..Default::default()
282→            }),
283→            category: Some("filesystem".into()),
284→            tags: vec!["fs".into(), "search".into()],
285→            timeout_secs: Some(30),
286→        }
287→    }
288→
289→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
290→        let pattern = call
291→            .input
292→            .get("pattern")
293→            .and_then(|v| v.as_str())
294→            .ok_or_else(|| ToolError::InvalidInput {
295→                message: "Missing or invalid 'pattern' argument".into(),
296→            })?;
297→
298→        let base_dir = call
299→            .input
300→            .get("path")
301→            .and_then(|v| v.as_str())
302→            .map(PathBuf::from)
303→            .unwrap_or_else(|| self.fs.workspace_root().to_path_buf());
304→
305→        let base_dir =
306→            self.fs
307→                .resolve(Path::new(&base_dir))
308→                .map_err(|e| ToolError::ExecutionFailed {
309→                    tool_name: "glob".into(),
310→                    message: e.to_string(),
311→                })?;
312→
313→        let full_pattern = base_dir.join(pattern).display().to_string();
314→
315→        let matches: Vec<String> = glob::glob(&full_pattern)
316→            .map_err(|e| ToolError::ExecutionFailed {
317→                tool_name: "glob".into(),
318→                message: format!("Invalid glob pattern: {e}"),
319→            })?
320→            .filter_map(Result::ok)
321→            .filter(|path| self.fs.resolve(path).is_ok())
322→            .map(|path| {
323→                path.strip_prefix(self.fs.workspace_root())
324→                    .map(|p| p.display().to_string())
325→                    .unwrap_or_else(|_| path.display().to_string())
326→            })
327→            .collect();
328→
329→        let count = matches.len();
330→
331→        Ok(ToolResult {
332→            call_id: call.call_id.clone(),
333→            tool_name: call.tool_name.clone(),
334→            output: json!({ "matches": matches, "count": count }),
335→            content: None,
336→            is_error: false,
337→        })
338→    }
339→}
