341→// ── GrepTool ─────────────────────────────────────────────────────────
342→
343→/// Searches file contents for a regex pattern within the workspace.
344→pub struct GrepTool {
345→    fs: Arc<dyn FsPort>,
346→}
347→
348→impl GrepTool {
349→    pub fn new(fs: Arc<dyn FsPort>) -> Self {
350→        Self { fs }
351→    }
352→}
353→
354→impl Tool for GrepTool {
355→    fn definition(&self) -> ToolDefinition {
356→        ToolDefinition {
357→            name: "grep".into(),
358→            description: "Search file contents for a regex pattern within the workspace.".into(),
359→            input_schema: json!({
360→                "type": "object",
361→                "properties": {
362→                    "pattern": { "type": "string", "description": "Regex pattern to search for" },
363→                    "path": { "type": "string", "description": "Directory to search (optional, defaults to workspace root)" },
364→                    "glob": { "type": "string", "description": "File glob filter (e.g. *.rs)" },
365→                    "max_matches": { "type": "integer", "description": "Maximum number of matches to return (default 100)" }
366→                },
367→                "required": ["pattern"]
368→            }),
369→            title: Some("Grep Search".into()),
370→            output_schema: None,
371→            annotations: Some(ToolAnnotations {
372→                read_only: true,
373→                idempotent: true,
374→                ..Default::default()
375→            }),
376→            category: Some("filesystem".into()),
377→            tags: vec!["fs".into(), "search".into()],
378→            timeout_secs: Some(60),
379→        }
380→    }
381→
382→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
383→        let pattern_str = call
384→            .input
385→            .get("pattern")
386→            .and_then(|v| v.as_str())
387→            .ok_or_else(|| ToolError::InvalidInput {
388→                message: "Missing or invalid 'pattern' argument".into(),
389→            })?;
390→
391→        let regex = Regex::new(pattern_str).map_err(|e| ToolError::ExecutionFailed {
392→            tool_name: "grep".into(),
393→            message: format!("Invalid regex pattern: {e}"),
394→        })?;
395→
396→        let base_dir = call
397→            .input
398→            .get("path")
399→            .and_then(|v| v.as_str())
400→            .map(PathBuf::from)
401→            .unwrap_or_else(|| self.fs.workspace_root().to_path_buf());
402→
403→        let base_dir =
404→            self.fs
405→                .resolve(Path::new(&base_dir))
406→                .map_err(|e| ToolError::ExecutionFailed {
407→                    tool_name: "grep".into(),
408→                    message: e.to_string(),
409→                })?;
410→
411→        let glob_filter = call.input.get("glob").and_then(|v| v.as_str());
412→
413→        let max_matches = call
414→            .input
415→            .get("max_matches")
416→            .and_then(serde_json::Value::as_u64)
417→            .unwrap_or(100) as usize;
418→
419→        let mut matches = Vec::new();
420→
421→        // Grep walks the filesystem directly for streaming reads (read-only).
422→        for entry in walkdir::WalkDir::new(&base_dir)
423→            .into_iter()
424→            .filter_map(Result::ok)
425→            .filter(|e| e.file_type().is_file())
426→        {
427→            let path = entry.path();
428→
429→            // Apply glob filter if specified
430→            if let Some(glob_pat) = glob_filter {
431→                let file_name = path.file_name().unwrap_or_default().to_string_lossy();
432→                let glob_pattern =
433→                    glob::Pattern::new(glob_pat).map_err(|e| ToolError::ExecutionFailed {
434→                        tool_name: "grep".into(),
435→                        message: format!("Invalid glob filter: {e}"),
436→                    })?;
437→                if !glob_pattern.matches(&file_name) {
438→                    continue;
439→                }
440→            }
441→
442→            // Skip large files (>10MB)
443→            if let Ok(metadata) = path.metadata() {
444→                if metadata.len() > 10 * 1024 * 1024 {
445→                    continue;
446→                }
447→            }
448→
449→            let Ok(file) = std::fs::File::open(path) else {
450→                continue;
451→            };
452→
453→            let reader = BufReader::new(file);
454→            for (line_no, line) in reader.lines().enumerate() {
455→                let Ok(line) = line else {
456→                    continue;
457→                };
458→
459→                if regex.is_match(&line) {
460→                    let rel_path = path
461→                        .strip_prefix(self.fs.workspace_root())
462→                        .map(|p| p.display().to_string())
463→                        .unwrap_or_else(|_| path.display().to_string());
464→
465→                    matches.push(json!({
466→                        "file": rel_path,
467→                        "line": line_no + 1,
468→                        "text": line
469→                    }));
470→
471→                    if matches.len() >= max_matches {
472→                        break;
473→                    }
474→                }
475→            }
476→
477→            if matches.len() >= max_matches {
478→                break;
479→            }
480→        }
481→
482→        let count = matches.len();
483→
484→        Ok(ToolResult {
485→            call_id: call.call_id.clone(),
486→            tool_name: call.tool_name.clone(),
487→            output: json!({ "matches": matches, "count": count }),
488→            content: None,
489→            is_error: false,
490→        })
491→    }
492→}
