  1→//! Hashline editing with Blake3 content-addressed line tags.
  2→//!
  3→//! Files are read with line numbers and content hashes. Edits must
  4→//! reference these tags, ensuring the agent edits the version it "sees".
  5→
  6→use aios_protocol::tool::{
  7→    Tool, ToolAnnotations, ToolCall, ToolContext, ToolDefinition, ToolError, ToolResult,
  8→};
  9→use blake3::Hasher;
 10→use praxis_core::FsPort;
 11→use serde::{Deserialize, Serialize};
 12→use serde_json::json;
 13→use std::path::Path;
 14→use std::sync::Arc;
 15→use thiserror::Error;
 16→
 17→/// A line of content with its hash tag.
 18→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
 19→pub struct HashedLine {
 20→    pub line_no: usize,
 21→    pub tag: String,
 22→    pub text: String,
 23→}
 24→
 25→/// An edit operation referencing a line by its hash tag.
 26→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
 27→#[serde(tag = "op", rename_all = "snake_case")]
 28→pub enum TaggedEditOp {
 29→    ReplaceLine { tag: String, new_text: String },
 30→    InsertAfterTag { tag: String, new_text: String },
 31→    DeleteLine { tag: String },
 32→}
 33→
 34→#[derive(Debug, Clone)]
 35→struct EditableLine {
 36→    anchor_tag: Option<String>,
 37→    text: String,
 38→}
 39→
 40→/// Compute hash tags for all lines in content.
 41→pub fn hash_lines(content: &str) -> Vec<HashedLine> {
 42→    content
 43→        .lines()
 44→        .enumerate()
 45→        .map(|(idx, line)| HashedLine {
 46→            line_no: idx + 1,
 47→            tag: line_tag(idx + 1, line),
 48→            text: line.to_string(),
 49→        })
 50→        .collect()
 51→}
 52→
 53→/// Render content with line numbers and hash tags for display.
 54→pub fn render_hashed_content(content: &str) -> String {
 55→    hash_lines(content)
 56→        .into_iter()
 57→        .map(|line| format!("{:>4} {} | {}", line.line_no, line.tag, line.text))
 58→        .collect::<Vec<_>>()
 59→        .join("\n")
 60→}
 61→
 62→/// Apply a sequence of tagged edit operations to content.
 63→pub fn apply_tagged_edits(content: &str, ops: &[TaggedEditOp]) -> Result<String, EditError> {
 64→    let initial_lines = hash_lines(content);
 65→
 66→    if initial_lines.is_empty() && !ops.is_empty() {
 67→        return Err(EditError::EmptyContent);
 68→    }
 69→
 70→    let mut editable: Vec<EditableLine> = initial_lines
 71→        .iter()
 72→        .map(|line| EditableLine {
 73→            anchor_tag: Some(line.tag.clone()),
 74→            text: line.text.clone(),
 75→        })
 76→        .collect();
 77→
 78→    for op in ops {
 79→        match op {
 80→            TaggedEditOp::ReplaceLine { tag, new_text } => {
 81→                let idx = find_anchor_index(&editable, tag)?;
 82→                editable[idx].text = new_text.clone();
 83→            }
 84→            TaggedEditOp::InsertAfterTag { tag, new_text } => {
 85→                let idx = find_anchor_index(&editable, tag)?;
 86→                editable.insert(
 87→                    idx + 1,
 88→                    EditableLine {
 89→                        anchor_tag: None,
 90→                        text: new_text.clone(),
 91→                    },
 92→                );
 93→            }
 94→            TaggedEditOp::DeleteLine { tag } => {
 95→                let idx = find_anchor_index(&editable, tag)?;
 96→                editable.remove(idx);
 97→            }
 98→        }
 99→    }
100→
101→    Ok(editable
102→        .into_iter()
103→        .map(|line| line.text)
104→        .collect::<Vec<_>>()
105→        .join("\n"))
106→}
107→
108→fn find_anchor_index(lines: &[EditableLine], tag: &str) -> Result<usize, EditError> {
109→    lines
110→        .iter()
111→        .position(|line| line.anchor_tag.as_deref() == Some(tag))
112→        .ok_or_else(|| EditError::StaleTag(tag.to_string()))
113→}
114→
115→fn line_tag(line_no: usize, text: &str) -> String {
116→    let mut hasher = Hasher::new();
117→    hasher.update(line_no.to_string().as_bytes());
118→    hasher.update(b":");
119→    hasher.update(text.as_bytes());
120→    let digest = hasher.finalize().to_hex().to_string();
121→    digest.chars().take(8).collect()
122→}
123→
124→/// Errors from the hashline editing system.
125→#[derive(Debug, Error)]
126→pub enum EditError {
127→    #[error("input content is empty; tags are required before edit")]
128→    EmptyContent,
129→    #[error("tag is stale or missing in current content: {0}")]
130→    StaleTag(String),
131→}
