133→// ── EditFileTool ──────────────────────────────────────────────────────
134→
135→/// Tool that applies hashline edits to files.
136→pub struct EditFileTool {
137→    fs: Arc<dyn FsPort>,
138→}
139→
140→impl EditFileTool {
141→    pub fn new(fs: Arc<dyn FsPort>) -> Self {
142→        Self { fs }
143→    }
144→}
145→
146→impl Tool for EditFileTool {
147→    fn definition(&self) -> ToolDefinition {
148→        ToolDefinition {
149→            name: "edit_file".into(),
150→            description: "Edits a file using line tags. Operations: replace_line, insert_after_tag, delete_line.".into(),
151→            input_schema: json!({
152→                "type": "object",
153→                "properties": {
154→                    "path": { "type": "string", "description": "Path to the file" },
155→                    "ops": {
156→                        "type": "array",
157→                        "items": {
158→                            "type": "object",
159→                            "oneOf": [
160→                                { "properties": { "op": { "const": "replace_line" }, "tag": { "type": "string" }, "new_text": { "type": "string" } }, "required": ["op", "tag", "new_text"] },
161→                                { "properties": { "op": { "const": "insert_after_tag" }, "tag": { "type": "string" }, "new_text": { "type": "string" } }, "required": ["op", "tag", "new_text"] },
162→                                { "properties": { "op": { "const": "delete_line" }, "tag": { "type": "string" } }, "required": ["op", "tag"] }
163→                            ]
164→                        }
165→                    }
166→                },
167→                "required": ["path", "ops"]
168→            }),
169→            title: Some("Edit File".into()),
170→            output_schema: None,
171→            annotations: Some(ToolAnnotations {
172→                destructive: true,
173→                ..Default::default()
174→            }),
175→            category: Some("filesystem".into()),
176→            tags: vec!["fs".into(), "edit".into()],
177→            timeout_secs: Some(30),
178→        }
179→    }
180→
181→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
182→        let path_str = call
183→            .input
184→            .get("path")
185→            .and_then(|v| v.as_str())
186→            .ok_or_else(|| ToolError::InvalidInput {
187→                message: "Missing or invalid 'path' argument".into(),
188→            })?;
189→
190→        let ops_value = call
191→            .input
192→            .get("ops")
193→            .ok_or_else(|| ToolError::InvalidInput {
194→                message: "Missing 'ops' argument".into(),
195→            })?;
196→
197→        let ops: Vec<TaggedEditOp> =
198→            serde_json::from_value(ops_value.clone()).map_err(|e| ToolError::InvalidInput {
199→                message: format!("Invalid 'ops' format: {e}"),
200→            })?;
201→
202→        let path = self
203→            .fs
204→            .resolve_for_write(Path::new(path_str))
205→            .map_err(|e| ToolError::PolicyViolation {
206→                message: e.to_string(),
207→            })?;
208→
209→        let content = self
210→            .fs
211→            .read_to_string(&path)
212→            .map_err(|e| ToolError::ExecutionFailed {
213→                tool_name: "edit_file".into(),
214→                message: format!("Failed to read file: {e}"),
215→            })?;
216→
217→        let new_content =
218→            apply_tagged_edits(&content, &ops).map_err(|e| ToolError::ExecutionFailed {
219→                tool_name: "edit_file".into(),
220→                message: format!("Edit failed: {e}"),
221→            })?;
222→
223→        self.fs
224→            .write(&path, new_content.as_bytes())
225→            .map_err(|e| ToolError::ExecutionFailed {
226→                tool_name: "edit_file".into(),
227→                message: format!("Failed to write file: {e}"),
228→            })?;
229→
