133→            .ok_or_else(|| ToolError::InvalidInput {
134→                message: "Missing or invalid 'key' argument".into(),
135→            })?;
136→
137→        let content = call
138→            .input
139→            .get("content")
140→            .and_then(|v| v.as_str())
141→            .ok_or_else(|| ToolError::InvalidInput {
142→                message: "Missing or invalid 'content' argument".into(),
143→            })?;
144→
145→        validate_memory_key(key).map_err(|msg| ToolError::InvalidInput { message: msg })?;
146→
147→        fs::create_dir_all(&self.memory_dir).map_err(|e| ToolError::ExecutionFailed {
148→            tool_name: "write_memory".into(),
149→            message: format!("Failed to create memory directory: {e}"),
150→        })?;
151→
152→        let file_path = self.memory_dir.join(format!("{key}.md"));
153→
154→        fs::write(&file_path, content).map_err(|e| ToolError::ExecutionFailed {
155→            tool_name: "write_memory".into(),
156→            message: format!("Failed to write memory file: {e}"),
157→        })?;
158→
159→        Ok(ToolResult {
160→            call_id: call.call_id.clone(),
161→            tool_name: call.tool_name.clone(),
162→            output: json!({ "success": true, "path": file_path }),
163→            content: None,
164→            is_error: false,
165→        })
166→    }
167→}
