169→/// Validate that a memory key is safe (alphanumeric, hyphens, underscores).
170→pub fn validate_memory_key(key: &str) -> Result<(), String> {
171→    if key.is_empty() {
172→        return Err("Memory key cannot be empty".into());
173→    }
174→    if key.len() > 64 {
175→        return Err("Memory key too long (max 64 characters)".into());
176→    }
177→    if !key
178→        .chars()
179→        .all(|c| c.is_alphanumeric() || c == '-' || c == '_')
180→    {
181→        return Err(
182→            "Memory key must contain only alphanumeric characters, hyphens, and underscores".into(),
183→        );
184→    }
185→    if key.starts_with('.') || key.contains("..") {
186→        return Err("Memory key cannot start with '.' or contain '..'".into());
187→    }
188→    Ok(())
189→}
