        let result = tool.execute(&call, &ctx).unwrap();

        assert_eq!(result.output["count"], 1);
        let matches = result.output["matches"].as_array().unwrap();
        assert!(matches[0]["file"].as_str().unwrap().contains("a.rs"));
    }

