    let McpTransport::Stdio {
        ref command,
        ref args,
    } = config.transport;

    let mut cmd = Command::new(command);
    cmd.args(args);

    let transport = TokioChildProcess::new(cmd).map_err(|e| McpError::Connection(e.to_string()))?;

